diff --git a/llvm/include/llvm/IR/DataLayout.h b/llvm/include/llvm/IR/DataLayout.h
index 2ad080e6d0cd..b4b8dbebd69c 100644
--- a/llvm/include/llvm/IR/DataLayout.h
+++ b/llvm/include/llvm/IR/DataLayout.h
@@ -631,7 +631,20 @@ inline TypeSize DataLayout::getTypeSizeInBits(Type *Ty) const {
     // Get the layout annotation... which is lazily created on demand.
     return getStructLayout(cast<StructType>(Ty))->getSizeInBits();
   case Type::IntegerTyID:
-    return TypeSize::getFixed(Ty->getIntegerBitWidth());
+    // Defensive check for potentially corrupted type objects
+    if (!Ty)
+      report_fatal_error("Null type in DataLayout::getTypeSizeInBits");
+    
+    // Check if the TypeID matches what we expect
+    if (Ty->getTypeID() != Type::IntegerTyID) {
+      // This should never happen, but if it does, return a safe default
+      return TypeSize::getFixed(64);
+    }
+    
+    // Try to get the bit width, but be defensive
+    if (auto *IT = dyn_cast<IntegerType>(Ty))
+      return TypeSize::getFixed(IT->getBitWidth());
+    return TypeSize::getFixed(64);
   case Type::HalfTyID:
   case Type::BFloatTyID:
     return TypeSize::getFixed(16);
